pub fn cdf_thread_init_static_qcat(qidx: u32) -> u32 {
    (qidx > 90) as u32 + (qidx > 140) as u32 + (qidx > 190) as u32
}

impl CdfContext {
    pub fn init_from_defaults(qcat: usize) -> Self {
        Self {
            coef: DEFAULT_COEF_CDF[qcat].clone(),
            m: DEFAULT_CDF.m.clone(),
            mv: DEFAULT_CDF.mv.clone(),
            dmv: DEFAULT_CDF.mv.clone(),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_cdf_struct_sizes() {
        assert_eq!(std::mem::size_of::<CdfModeContext>(), 6992);
        assert_eq!(std::mem::size_of::<CdfCoefContext>(), 9312);
        assert_eq!(std::mem::size_of::<CdfMvContext>(), 336);
        assert_eq!(std::mem::size_of::<CdfDefaultContext>(), 7328);
    }

    #[test]
    fn test_default_cdf_first_values() {
        assert_eq!(DEFAULT_CDF.m.data[0], 7226);
        assert_eq!(DEFAULT_CDF.m.data[1], 15872);
        assert_eq!(DEFAULT_CDF.mv.data[0], 28308);
    }

    #[test]
    fn test_qcat_calculation() {
        assert_eq!(cdf_thread_init_static_qcat(50), 0);
        assert_eq!(cdf_thread_init_static_qcat(100), 1);
        assert_eq!(cdf_thread_init_static_qcat(150), 2);
        assert_eq!(cdf_thread_init_static_qcat(200), 3);
    }

    #[test]
    fn test_init_from_defaults() {
        let ctx = CdfContext::init_from_defaults(0);
        assert_eq!(ctx.m.data[0], 7226);
        assert_eq!(ctx.coef.data[0], 7009);
    }
}
